<style>
    .wa-page{--wa:#16a34a;--wa-dark:#087b35;--ink:#172033;--muted:#69758c;--line:#e5eaf2;padding-bottom:38px}.wa-hero{margin-top:18px;padding:26px 30px;border-radius:22px;background:linear-gradient(125deg,#064e3b,#0f9f55 58%,#22c55e);color:#fff;box-shadow:0 20px 48px rgba(22,163,74,.2)}.wa-hero h1{color:#fff;margin:0 0 7px;font-weight:900}.wa-hero p{margin:0;color:rgba(255,255,255,.8)}.wa-toolbar{display:flex;flex-wrap:wrap;gap:10px;margin-top:18px}.wa-btn{display:inline-flex;align-items:center;justify-content:center;gap:8px;padding:10px 15px;border:0;border-radius:11px;text-decoration:none;font-weight:800;cursor:pointer}.wa-btn-light{background:#fff;color:#087b35}.wa-btn-primary{background:var(--wa);color:#fff}.wa-btn-outline{border:1px solid var(--line);background:#fff;color:#334155}.wa-grid{display:grid;grid-template-columns:minmax(270px,360px) minmax(0,1fr);gap:22px;margin-top:24px}.wa-card{border:1px solid var(--line);border-radius:18px;background:#fff;box-shadow:0 10px 35px rgba(30,41,59,.06);overflow:hidden}.wa-card-head{display:flex;align-items:center;justify-content:space-between;gap:12px;padding:18px 20px;border-bottom:1px solid var(--line)}.wa-card-head h2{margin:0;color:var(--ink);font-size:17px;font-weight:900}.wa-search{width:100%;padding:11px 13px;border:1px solid var(--line);border-radius:10px}.wa-list{max-height:640px;overflow:auto}.wa-conversation{display:flex;gap:12px;padding:14px 18px;border-bottom:1px solid var(--line);color:inherit;text-decoration:none;transition:.15s}.wa-conversation:hover{background:#f2fbf5}.wa-avatar{width:44px;height:44px;display:grid;place-items:center;flex:0 0 44px;border-radius:50%;background:#dcfce7;color:#087b35;font-weight:900}.wa-conversation-body{min-width:0;flex:1}.wa-conversation-top{display:flex;justify-content:space-between;gap:8px}.wa-name{color:var(--ink);font-weight:850;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.wa-time,.wa-preview{color:var(--muted);font-size:12px}.wa-preview{margin-top:4px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.wa-unread{min-width:22px;height:22px;display:grid;place-items:center;border-radius:50%;background:var(--wa);color:#fff;font-size:11px}.wa-empty{padding:50px 22px;text-align:center;color:var(--muted)}.wa-empty i{font-size:32px;color:#86efac;margin-bottom:12px}.wa-campaign{display:grid;grid-template-columns:minmax(0,1fr) auto;gap:10px;padding:14px 18px;border-bottom:1px solid var(--line)}.wa-campaign strong{display:block;color:var(--ink)}.wa-status{display:inline-flex;padding:5px 8px;border-radius:999px;background:#f1f5f9;color:#475569;font-size:11px;font-weight:800}.wa-alert{margin-top:18px;padding:14px 16px;border:1px solid #fde68a;border-radius:13px;background:#fffbeb;color:#92400e}.wa-form{margin-top:24px;padding:24px;border:1px solid var(--line);border-radius:20px;background:#fff}.wa-form-grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:18px}.wa-field label{display:block;margin-bottom:7px;color:var(--ink);font-weight:800}.wa-field input,.wa-field select,.wa-field textarea{width:100%;padding:11px 13px;border:1px solid var(--line);border-radius:10px;background:#fff}.wa-field textarea{min-height:130px;resize:vertical}.wa-field small{display:block;margin-top:6px;color:var(--muted)}.wa-span-2{grid-column:1/-1}.wa-recipient-list{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:8px;max-height:390px;overflow:auto;padding:10px;border:1px solid var(--line);border-radius:12px}.wa-recipient{display:flex;align-items:center;gap:9px;padding:10px;border-radius:9px;background:#f8fafc}.wa-chat{display:flex;flex-direction:column;min-height:650px}.wa-chat-head{display:flex;align-items:center;gap:12px;padding:17px 20px;border-bottom:1px solid var(--line)}.wa-messages{flex:1;padding:22px;overflow:auto;background:#f4f7f5}.wa-bubble{width:fit-content;max-width:min(78%,650px);margin-bottom:11px;padding:11px 14px;border-radius:15px;background:#fff;box-shadow:0 2px 8px rgba(15,23,42,.06)}.wa-bubble.outbound{margin-inline-start:auto;background:#d9fdd3}.wa-bubble-meta{display:flex;justify-content:flex-end;gap:7px;margin-top:5px;color:#64748b;font-size:10px}.wa-reply{padding:15px;border-top:1px solid var(--line);background:#fff}.wa-reply form{display:flex;gap:10px}.wa-reply textarea{flex:1;min-height:48px;max-height:130px;padding:11px;border:1px solid var(--line);border-radius:11px;resize:vertical}.wa-code{padding:12px;border-radius:10px;background:#0f172a;color:#d1fae5;font-family:monospace;overflow-wrap:anywhere}.wa-secret{filter:blur(5px);user-select:none}.wa-secret:hover{filter:none}.wa-errors{margin:15px 0;padding:12px 15px;border-radius:11px;background:#fef2f2;color:#b91c1c}body.dark .wa-page{--ink:#eef2ff;--muted:#aab4c8;--line:#2b3549}body.dark .wa-card,body.dark .wa-form,body.dark .wa-btn-outline,body.dark .wa-field input,body.dark .wa-field select,body.dark .wa-field textarea,body.dark .wa-reply{background:#172033}body.dark .wa-recipient{background:#202a3d}body.dark .wa-messages{background:#111827}body.dark .wa-bubble{background:#253047;color:#e5e7eb}body.dark .wa-bubble.outbound{background:#14532d}@media(max-width:900px){.wa-grid{grid-template-columns:1fr}.wa-form-grid,.wa-recipient-list{grid-template-columns:1fr}}@media(max-width:575px){.wa-hero,.wa-form{padding:20px}.wa-toolbar .wa-btn{width:100%}.wa-bubble{max-width:90%}}
</style>
